const now = new Date();
const dateline = 'Week of ' + now.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric', timeZone: 'America/New_York' });
// Pull current Volume + Issue Number from the Settings table (Fetch Settings).
const s = (($('Fetch Settings').first() || {}).json) || {};
function num(v, dflt) { const n = parseInt(v, 10); return isNaN(n) ? dflt : n; }
const vol = num(s['Volume'], 1);
const no  = num(s['Issue Number'], 3);          // THIS issue renders this number
const settingsRecordId = s['id'] || '';
return [{ json: { dateline, vol, no, nextIssue: no + 1, settingsRecordId } }];

