parameters.jsCode:
// Collect Verifications — aggregate the 6 Verify nodes' {passed,flags} outputs.
// Determines block vs warn; gates the draft downstream.
function claudeJSON(resp) {
  // Robust: verifiers sometimes wrap JSON in ```json fences AND add prose before/
  // after it. Extract the JSON regardless, or a fragile parse drops all flags and
  // produces a FALSE clean pass.
  try {
    const c = (resp && resp.content) || [];
    let t = c.filter(b => b && b.type === 'text').map(b => b.text).join('');
    const m = t.match(/```(?:json)?\s*([\s\S]*?)```/i);
    if (m) t = m[1];
    t = t.trim();
    const start = t.search(/[\{\[]/);
    if (start > 0) t = t.slice(start);
    try { return JSON.parse(t); } catch (e) {}
    const last = Math.max(t.lastIndexOf('}'), t.lastIndexOf(']'));
    if (last >= 0) { try { return JSON.parse(t.slice(0, last + 1)); } catch (e) {} }
    return null;
  } catch (e) { return null; }
}
const VERIFY = {
  'Verify Lede': 'lede',
  'Verify Feature': 'lead-story',
  'Verify Signals': 'campus-stories',
  'Verify Connectors': 'connector-table',
  'Verify Flags': 'policy-flags',
  'Verify Pricing': 'pricing-context'
};
let flags = [];
for (const node in VERIFY) {
  let r = null;
  try { r = $(node).first().json; } catch (e) { r = null; }
  const v = claudeJSON(r);
  if (v && Array.isArray(v.flags)) {
    for (const f of v.flags) {
      const sec = f.section || VERIFY[node];
      const type = Number(f.type);
      // DETERMINISTIC severity (computed here, not trusted from the verifier):
      // only HARD fabrications halt the draft — type 1 (a specific number not in
      // source) or type 2 (a project/company name not in source). Types 3-5
      // (duplicate project, price/capex framing, contextual contradiction) and any
      // untyped/uncertain flag are 'warn'. Pricing section is always 'warn'.
      let severity = (type === 1 || type === 2) ? 'block' : 'warn';
      const isPricing = (node === 'Verify Pricing') || /pricing/i.test(String(sec));
      if (isPricing) severity = 'warn';
      // APPROVED ENTITY FACTS: the Generate prompts intentionally add user-authoritative
      // real-world corrections (Hut 8 = Beacon Point campus + its 352MW lease / $4.25B note /
      // 1,000MW AEP Texas interconnect; Stark's $140M raise; Sagebrush BTM gas) that are NOT
      // in the Airtable source, so the verifier flags them as type 1/2. The prompt-level
      // exemption is unreliable (the LLM still flags), so downgrade these to 'warn'
      // deterministically here — they surface in the email but never halt the draft.
      const APPROVED = /(hut 8|beacon point|sagebrush|352\s*mw|\$?\s*4\.25\s*b|4\.25\s*billion|aep texas|\$?\s*140\s*m(illion)?)/i;
      if (severity === 'block' && APPROVED.test(String(f.issue || ''))) severity = 'warn';
      flags.push({ section: sec, issue: String(f.issue || ''), type: (Number.isFinite(type) ? type : null), severity });
    }
  }
}
const blocks = flags.filter(f => f.severity === 'block');
const warns = flags.filter(f => f.severity === 'warn');
return [{ json: { hasBlock: blocks.length > 0, blocks, warns, allFlags: flags } }];

