// Cross-Section Dedup — after the HTML is assembled, flag any company/project
// name that appears in MORE THAN TWO sections as a 'warn'. Merges with the
// verification warns and carries them forward to Store Draft / the draft email.
function claudeJSON(resp) {
  try {
    const c = (resp && resp.content) || [];
    let t = c.filter(b => b && b.type === 'text').map(b => b.text).join('');
    const m = t.match(/```(?:json)?\s*([\s\S]*?)```/i);
    if (m) t = m[1];
    t = t.trim();
    const start = t.search(/[\{\[]/);
    if (start > 0) t = t.slice(start);
    try { return JSON.parse(t); } catch (e) {}
    const last = Math.max(t.lastIndexOf('}'), t.lastIndexOf(']'));
    if (last >= 0) { try { return JSON.parse(t.slice(0, last + 1)); } catch (e) {} }
    return null;
  } catch (e) { return null; }
}
const j = $input.first().json; // from Code — Inject: { html, vol, no, dateline }

const lede = (claudeJSON($('Generate Lede').first().json) || {}).lede || '';
const feature = claudeJSON($('Generate Feature').first().json) || {};
const stories = claudeJSON($('Generate Signals').first().json) || [];
const connectors = claudeJSON($('Generate Connectors').first().json) || [];
const flags = claudeJSON($('Generate Flags').first().json) || [];
const pricing = claudeJSON($('Generate Pricing').first().json) || {};

const sectionText = {
  lede: String(lede),
  feature: [feature.title, feature.dek].concat(feature.paragraphs || []).join(' '),
  campus: (Array.isArray(stories) ? stories : []).map(s => [s.hed, s.dek].concat(s.paragraphs || []).join(' ')).join(' '),
  connectors: (Array.isArray(connectors) ? connectors : []).map(c => [c.market_tag, c.load_name, c.load_note, c.supply_note, c.strategic_note].join(' ')).join(' '),
  flags: (Array.isArray(flags) ? flags : []).map(f => [f.entity, f.note].join(' ')).join(' '),
  pricing: (pricing.paragraphs || []).join(' ')
};

// candidate company/project names from structured fields
const cands = new Set();
(Array.isArray(connectors) ? connectors : []).forEach(c => { if (c.load_name) cands.add(String(c.load_name).trim()); });
(Array.isArray(flags) ? flags : []).forEach(f => { if (f.entity) { const e = String(f.entity).split('·')[0].split('-')[0].trim(); if (e) cands.add(e); } });
(Array.isArray(stories) ? stories : []).forEach(s => { if (s.hed) { const m = String(s.hed).match(/^([A-Z][A-Za-z0-9&.\-]+(?:\s+[A-Z][A-Za-z0-9&.\-]+){0,2})/); if (m) cands.add(m[1].replace(/['’]s$/, '').trim()); } });

const xflags = [];
for (const name of cands) {
  if (!name || name.length < 4) continue;
  const needle = name.toLowerCase();
  let count = 0;
  for (const sec in sectionText) { if (String(sectionText[sec]).toLowerCase().indexOf(needle) !== -1) count++; }
  if (count > 2) xflags.push({ section: 'cross-section', issue: '"' + name + '" appears in ' + count + ' sections', severity: 'warn' });
}

let warns = [];
try { warns = ($('Collect Verifications').first().json.warns || []).slice(); } catch (e) { warns = []; }
warns = warns.concat(xflags);
return [{ json: Object.assign({}, j, { warns }) }];

// Select Signals — curate the signals that feed every Generate/Verify node.
// Priority: (a) location populated, (b) Actionability desc, (c) CREATED_TIME desc
// tiebreak (recency), then a regional diversity guard (no single ISO/region > 5 of 14).
// Effective Actionability falls back to the categorical Signal Score (High->4,
// Medium->2) when the numeric field is missing/invalid, so signals from secondary
// ingestion paths (Status=New, EIA spikes) still compete instead of being invisible.
const CAP_PER_REGION = 5;
const TARGET = 14;            // how many we ultimately pick (feeds ALL sections)
const MIN_REQUIRED = 8;       // section minimums to NOT expand: lead(1)+grid(4)+flags(3)

function stateOf(loc) {
  const s = String(loc || '');
  const m = s.match(/\b(TX|CA|VA|OH|IL|PA|GA|AZ|NV|WA|OR|NM|CO|MI|IN|WI|MN|MO|KS|OK|LA|MS|AL|TN|KY|NC|SC|FL|NY|NJ|MD|WV|IA|NE|ND|SD|MT|WY|ID|UT|AR|CT|MA|ME|NH|VT|RI|DE|DC)\b/);
  if (m) return m[1];
  const names = { Texas:'TX', California:'CA', Virginia:'VA', Ohio:'OH', Illinois:'IL', Pennsylvania:'PA',
    Georgia:'GA', Arizona:'AZ', Nevada:'NV', Washington:'WA', Michigan:'MI', Indiana:'IN', Mississippi:'MS',
    Tennessee:'TN', Kansas:'KS', 'New York':'NY', Wisconsin:'WI', Minnesota:'MN', Missouri:'MO', Florida:'FL' };
  for (const k in names) if (s.toLowerCase().includes(k.toLowerCase())) return names[k];
  return '';
}
// approximate state -> ISO/region (TX->ERCOT is the one that matters most for the cap)
const ISO = { TX:'ERCOT', CA:'CAISO', NY:'NYISO',
  VA:'PJM', OH:'PJM', PA:'PJM', NJ:'PJM', MD:'PJM', DE:'PJM', DC:'PJM', WV:'PJM', NC:'PJM', KY:'PJM', IL:'PJM',
  MN:'MISO', WI:'MISO', IA:'MISO', MO:'MISO', ND:'MISO', SD:'MISO', AR:'MISO', LA:'MISO', MS:'MISO', MI:'MISO', IN:'MISO',
  AZ:'WECC', NV:'WECC', WA:'WECC', OR:'WECC', CO:'WECC', NM:'WECC', UT:'WECC', ID:'WECC', MT:'WECC', WY:'WECC',
  FL:'FRCC', GA:'SERC', TN:'SERC', AL:'SERC', SC:'SERC', KS:'SPP', OK:'SPP', NE:'SPP' };
function regionOf(loc) { const st = stateOf(loc); return ISO[st] || st || 'Unknown'; }

function effAct(r) {
  let a = parseInt(r['Actionability'], 10);
  if (a >= 1 && a <= 5) return a;
  const sc = r['Signal Score'];
  return sc === 'High' ? 4 : sc === 'Medium' ? 2 : 0;
}

const rows = $('Fetch Market Signals').all().map(i => i.json);
const NOW = Date.now();
function ageDays(ct) { const t = ct ? new Date(ct).getTime() : NaN; return isNaN(t) ? Infinity : (NOW - t) / 86400000; }

// US-ONLY gate: Claude-classified Country field wins; else a conservative Location/Company
// heuristic that excludes clearly-non-US geographies WITHOUT dropping US namesake towns
// (New Mexico / New England stripped; ambiguous city names deliberately excluded from the list).
function isUSsignal(r) {
  const c = String(r['Country'] || '').trim().toLowerCase();
  if (c) return /^(us|usa|u\.?s\.?a?\.?|united states|united states of america)$/.test(c);
  const txt = (String(r['Location'] || '') + ' ' + String(r['Company'] || '')).toLowerCase()
    .replace(/new mexico/g, '').replace(/new england/g, '');
  const NONUS = /\b(canada|canadian|ontario|quebec|alberta|manitoba|saskatchewan|british columbia|nova scotia|newfoundland|united kingdom|uk|great britain|scotland|wales|northern ireland|republic of ireland|germany|france|spain|italy|netherlands|sweden|norway|finland|denmark|poland|belgium|switzerland|austria|portugal|greece|europe|european|india|japan|south korea|north korea|singapore|australia|new zealand|brazil|chile|argentina|colombia|united arab emirates|saudi arabia|qatar|kuwait|israel|nigeria|egypt|malaysia|indonesia|vietnam|thailand|philippines|taiwan|hong kong)\b/;
  return !NONUS.test(txt);
}

// (a) location must be populated
const located = rows.filter(r => String(r['Location'] || '').trim() !== '' && isUSsignal(r))
  .map(r => ({
    id: r['id'], company: r['Company'], detail: r['Signal Detail'], category: r['Signal Type'],
    location: r['Location'], mw: r['MW Size'], actionability: effAct(r),
    createdTime: r['createdTime'] || '', region: regionOf(r['Location']),
    _age: ageDays(r['createdTime'])
  }));

// PRIMARY GATE = Created within the last 7 days — only THIS WEEK's signals are eligible
// for the current issue. (The 21-day Last Featured cooldown is applied at the fetch as the
// SECONDARY filter, so the pool here is already cooldown-clean.) Expand the window
// 7 -> 14 days ONLY when the 7-day pool has fewer than the section minimums
// (MIN_REQUIRED = lead 1 + grid 4 + flags 3); then fall back to the full eligible
// (<=30d, not-in-cooldown) pool. The 30-day fetch is just the buffer for that fallback.
let windowDays = 7;
let pool = located.filter(r => r._age <= 7);
if (pool.length < MIN_REQUIRED) { windowDays = 14; pool = located.filter(r => r._age <= 14); }
if (pool.length < MIN_REQUIRED) { windowDays = 30; pool = located.filter(r => r._age <= 30); }

// (b) Actionability desc, (c) CREATED_TIME desc tiebreak
pool = pool.sort((a, b) => (b.actionability - a.actionability) ||
                           String(b.createdTime).localeCompare(String(a.createdTime)));

// regional diversity guard: fill respecting the per-region cap; defer over-cap items
const counts = {}; const picked = []; const deferred = [];
for (const r of pool) {
  if (picked.length >= TARGET) break;
  counts[r.region] = counts[r.region] || 0;
  if (counts[r.region] < CAP_PER_REGION) { picked.push(r); counts[r.region]++; }
  else deferred.push(r);  // would exceed cap -> replaced by next-highest other-region signals
}
// only if too few other-region signals exist to reach 14, backfill from deferred
for (const r of deferred) { if (picked.length >= TARGET) break; picked.push(r); counts[r.region] = (counts[r.region]||0)+1; }

const top14 = picked.slice(0, TARGET).map(({ _age, ...keep }) => keep);
return [{ json: { top14, regionCounts: counts, windowDays, poolSize: pool.length, totalFetched: rows.length } }];

const raw = $('Fetch Tariff Updates').all().map(i => i.json);
function fld(r, name) { return (r && r.fields && r.fields[name] !== undefined) ? r.fields[name] : (r ? r[name] : undefined); }
const recs = raw.filter(r => fld(r, 'Record Type') === 'Tariff Update');
const records = recs.map(r => ({
  iso: fld(r, 'Location') || String(fld(r, 'Company') || '').replace('ISO Tariff Update — ', '').trim(),
  detail: fld(r, 'Signal Detail') || '',
  url: fld(r, 'Source URL') || '',
}));
return [{ json: { count: records.length, records } }];

const ids = (($('Read Draft').first().json.usedSignalIds) || []).filter(Boolean);
const today = new Date().toISOString().slice(0, 10);
return ids.map(id => ({ json: { record_id: id, today } }));

const ids = (($('Read Draft').first().json.usedQueueIds) || []).filter(Boolean);
const today = new Date().toISOString().slice(0, 10);
return ids.map(id => ({ json: { record_id: id, today } }));

// Aggregate live queue MW by ISO/Region for the Connector Markets supply snapshot.
const US_REGIONS = new Set(['MISO','PJM','ERCOT','CAISO','SPP','NYISO','ISONE','ISO-NE','SOUTHEAST','SERC','WEST','WECC','FRCC']);
const NON_US_STATES = new Set(['QC','QUEBEC','ON','ONTARIO','AB','ALBERTA','BC','BRITISH COLUMBIA','MB','MANITOBA','SK','SASKATCHEWAN','NS','NOVA SCOTIA','NB','NEW BRUNSWICK','NL','NEWFOUNDLAND','PE','PEI','YT','NT','NU']);
function isUSqueue(r) {
  const reg = String(r['Region'] || '').toUpperCase().trim();
  const st = String(r['State'] || '').toUpperCase().trim();
  if (NON_US_STATES.has(st)) return false;          // Canadian/foreign province
  if (reg && !US_REGIONS.has(reg)) return false;    // non-US region
  return true;
}
const rows = $('Fetch Queue Records').all().map(i => i.json).filter(isUSqueue);  // US-only
const by = {};
for (const r of rows) {
  if (String(r['Status'] || '').toLowerCase() === 'completed') continue;
  const region = r['Region'] || r['State'] || 'Other';
  const mw = parseFloat(r['MW Capacity']) || 0;
  const tech = r['Generation Type'] || 'Mixed';
  if (!by[region]) by[region] = { region, mw: 0, count: 0, techs: {} };
  by[region].mw += mw; by[region].count++;
  by[region].techs[tech] = (by[region].techs[tech] || 0) + mw;
}
const byRegion = Object.values(by).map(x => {
  const t = Object.entries(x.techs).sort((a, b) => b[1] - a[1])[0];
  return { region: x.region, mw_total: Math.round(x.mw), count: x.count, top_tech: t ? t[0] : 'Mixed' };
}).sort((a, b) => b.mw_total - a.mw_total);
return [{ json: { byRegion } }];
